using System.ComponentModel.DataAnnotations;

namespace sv_4367b35fae90460f876d4d8b569a9204.Models;

public class RegistrationModel
{
    [Required(ErrorMessage = "Attendee name is required.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    public string Email { get; set; } = string.Empty;

    [Range(0, 5, ErrorMessage = "Number of guests must be between 0 and 5.")]
    public int NumberOfGuests { get; set; }

    [Required(ErrorMessage = "Please select a preferred session.")]
    public string PreferredSession { get; set; } = string.Empty;

    public string? DietaryRequirements { get; set; }
}

using sv_4367b35fae90460f876d4d8b569a9204.Models;

namespace sv_4367b35fae90460f876d4d8b569a9204.Services;

public class RegistrationService
{
    /// <summary>
    /// Validates a registration against server-side rules.
    /// Returns a dictionary of field name → error message for any failures.
    /// An empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAsync(RegistrationModel model)
    {
        var errors = new Dictionary<string, string>();

        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(model.Email)] = "This email is already registered.";
        }

        return Task.FromResult(errors);
    }
}

@page "/register"
@rendermode InteractiveServer
@using sv_4367b35fae90460f876d4d8b569a9204.Models
@using sv_4367b35fae90460f876d4d8b569a9204.Services
@inject RegistrationService RegistrationService

<PageTitle>Event Registration</PageTitle>

<h3>Event Registration</h3>

@if (isSubmitted)
{
    <div class="alert alert-success mt-3">
        <strong>Registration successful!</strong> Thank you, @model.Name.
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="register" class="mt-3" style="max-width: 500px;">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="name" class="form-label">Attendee Name</label>
            <InputText id="name" @bind-Value="model.Name" class="form-control" />
            <ValidationMessage For="() => model.Name" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" @bind-Value="model.Email" class="form-control" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label for="guests" class="form-label">Number of Guests</label>
            <InputNumber id="guests" @bind-Value="model.NumberOfGuests" class="form-control" />
            <ValidationMessage For="() => model.NumberOfGuests" />
        </div>

        <div class="mb-3">
            <label for="session" class="form-label">Preferred Session</label>
            <InputSelect id="session" @bind-Value="model.PreferredSession" class="form-select">
                <option value="">-- Select --</option>
                <option value="Morning">Morning</option>
                <option value="Afternoon">Afternoon</option>
                <option value="Evening">Evening</option>
            </InputSelect>
            <ValidationMessage For="() => model.PreferredSession" />
        </div>

        <div class="mb-3">
            <label for="dietary" class="form-label">Special Dietary Requirements</label>
            <InputTextArea id="dietary" @bind-Value="model.DietaryRequirements" class="form-control" rows="3" />
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isProcessing">
            @if (isProcessing)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
            }
            Register
        </button>
    </EditForm>
}

@code {
    private RegistrationModel model = new();
    private bool isSubmitted;
    private bool isProcessing;

    private async Task HandleSubmit()
    {
        isProcessing = true;

        var serverErrors = await RegistrationService.ValidateAsync(model);

        if (serverErrors.Count > 0)
        {
            var messageStore = new ValidationMessageStore(editContext!);
            foreach (var (field, message) in serverErrors)
            {
                messageStore.Add(editContext!.Field(field), message);
            }
            editContext!.NotifyValidationStateChanged();
            isProcessing = false;
            return;
        }

        isSubmitted = true;
        isProcessing = false;
    }

    private EditContext? editContext;

    protected override void OnInitialized()
    {
        editContext = new EditContext(model);
    }
}

